/* MessMate - Custom Styles */

/* CSS Variables for consistent theming */
:root {
    --mess-primary: #28a745;
    --mess-secondary: #d4edda;
    --mess-accent: #20c997;
    --mess-light: #f8f9fa;
    --mess-dark: #1e4b24;
    --mess-warning: #ffc107;
    --mess-success: #28a745;
    --mess-danger: #dc3545;
    --mess-info: #17a2b8;
}

/* Global Styles */
body {
    font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
    background: linear-gradient(rgba(46, 125, 50, 0.7), rgba(76, 175, 80, 0.7)), 
                url('https://images.pexels.com/photos/3952060/pexels-photo-3952060.jpeg?auto=compress&cs=tinysrgb&w=1260&h=750&dpr=2');
